import pytest
import time
import threading
import random
from collections import OrderedDict
from typing import Any, Optional
from main import LRUCacheWithTTL

# Fixtures pour les configurations de cache
@pytest.fixture
def cache_10k_100_threads():
    cache = LRUCacheWithTTL(max_size=10_000, ttl=5)
    return cache

@pytest.fixture
def cache_1M_1k_threads():
    cache = LRUCacheWithTTL(max_size=1_000_000, ttl=3600)
    return cache

@pytest.fixture
def cache_10k_50_threads():
    cache = LRUCacheWithTTL(max_size=10_000, ttl=1)
    return cache

@pytest.fixture
def cache_50k_200_threads():
    cache = LRUCacheWithTTL(max_size=50_000, ttl=None)  # TTL variable
    return cache

@pytest.fixture
def cache_10k_100_threads_write_only():
    cache = LRUCacheWithTTL(max_size=10_000, ttl=0)
    return cache

# Tests de charge avec Locust (simulés via pytest-benchmark)
def test_load_10k_100_threads_read_80_write_20(benchmark, cache_10k_100_threads):
    """Test de charge : 10k clés, 100 threads, 80% lecture/20% écriture, TTL 5s"""
    def _load():
        for i in range(10_000):
            cache_10k_100_threads.set(f"key_{i}", f"value_{i}")
        for _ in range(100):
            for i in range(8000):
                cache_10k_100_threads.get(f"key_{i}")
            for i in range(2000):
                cache_10k_100_threads.set(f"key_{i}", f"value_{i}_updated")

    result = benchmark(_load)
    assert result.stats["p99"] < 1.0  # p99 < 1ms
    assert result.stats["ops_per_sec"] > 10_000  # débit > 10k ops/s
    assert cache_10k_100_threads.eviction_count / 10_000 < 0.05  # taux d'éviction < 5%


def test_load_1M_1k_threads_read_90_write_10(benchmark, cache_1M_1k_threads):
    """Test de charge extrême : 1M clés, 1k threads, 90% lecture/10% écriture, TTL 1h"""
    def _load():
        for i in range(1_000_000):
            cache_1M_1k_threads.set(f"key_{i}", f"value_{i}")
        for _ in range(1000):
            for i in range(900_000):
                cache_1M_1k_threads.get(f"key_{i}")
            for i in range(100_000):
                cache_1M_1k_threads.set(f"key_{i}", f"value_{i}_updated")

    result = benchmark(_load)
    assert result.stats["p99"] < 5.0  # p99 < 5ms (tolérance pour charge extrême)
    assert result.stats["ops_per_sec"] > 50_000  # débit > 50k ops/s


def test_load_10k_50_threads_read_50_write_50(benchmark, cache_10k_50_threads):
    """Test de cohérence : 10k clés, 50 threads, 50% lecture/50% écriture, TTL 1s"""
    def _load():
        for i in range(10_000):
            cache_10k_50_threads.set(f"key_{i}", f"value_{i}")
        for _ in range(50):
            for i in range(5000):
                cache_10k_50_threads.get(f"key_{i}")
            for i in range(5000):
                cache_10k_50_threads.set(f"key_{i}", f"value_{i}_updated")

    result = benchmark(_load)
    assert result.stats["p99"] < 2.0  # p99 < 2ms
    assert cache_10k_50_threads.ttl_consistency_rate > 0.95  # cohérence des TTL > 95%


def test_load_50k_200_threads_mixed_ttl(benchmark, cache_50k_200_threads):
    """Test TTL variable : 50k clés, 200 threads, opérations mixtes, TTL variable"""
    def _load():
        for i in range(50_000):
            ttl = random.choice([1, 10, 3600])  # TTL variable
            cache_50k_200_threads.set(f"key_{i}", f"value_{i}", ttl=ttl)
        for _ in range(200):
            for i in range(50_000):
                cache_50k_200_threads.get(f"key_{i}")

    result = benchmark(_load)
    assert result.stats["p99"] < 3.0  # p99 < 3ms


def test_load_10k_100_threads_write_only(benchmark, cache_10k_100_threads_write_only):
    """Test overhead écriture : 10k clés, 100 threads, 100% écriture, TTL 0s"""
    def _load():
        for i in range(10_000):
            cache_10k_100_threads_write_only.set(f"key_{i}", f"value_{i}")
        for _ in range(100):
            for i in range(10_000):
                cache_10k_100_threads_write_only.set(f"key_{i}", f"value_{i}_updated")

    result = benchmark(_load)
    assert result.stats["p99"] < 1.5  # p99 < 1.5ms
    assert result.stats["ops_per_sec"] > 8_000  # débit > 8k ops/s (tolérance pour overhead)

# Tests de thread-safety et deadlocks
def test_thread_safety_no_deadlocks(cache_10k_100_threads):
    """Test de stress pour détecter les deadlocks avec 100 threads pendant 1h"""
    def _worker(cache, worker_id):
        for i in range(1000):
            key = f"key_{worker_id}_{i}"
            cache.set(key, f"value_{worker_id}_{i}")
            cache.get(key)
            time.sleep(0.001)

    threads = []
    for i in range(100):
        t = threading.Thread(target=_worker, args=(cache_10k_100_threads, i))
        threads.append(t)
        t.start()

    for t in threads:
        t.join(timeout=3600)  # Timeout de 1h

    assert len(threading.enumerate()) == 1  # Vérification absence de threads zombies
    assert cache_10k_100_threads.deadlock_detected is False  # Métrique interne


def test_ttl_consistency(cache_10k_50_threads):
    """Test de cohérence des TTL après expiration"""
    cache_10k_50_threads.set("key1", "value1", ttl=1)
    time.sleep(1.1)
    assert cache_10k_50_threads.get("key1") is None
    assert "key1" not in cache_10k_50_threads._cache


def test_lock_timeout(cache_10k_100_threads):
    """Test des timeouts sur les verrous"""
    with pytest.raises(TimeoutError):
        cache_10k_100_threads._lock.acquire(timeout=0.001)
        cache_10k_100_threads._lock.acquire(timeout=0.001)  # Deadlock simulé

# Tests de performance comparatifs (simulés)
def test_benchmark_latency_p99(benchmark):
    """Benchmark de latence p99 pour différentes configurations de TTL"""
    cache = LRUCacheWithTTL(max_size=10_000)

    def _benchmark_ttl(ttl):
        cache.set("key", "value", ttl=ttl)
        for _ in range(1000):
            cache.get("key")

    results = {}
    for ttl in [1, 10, 3600]:
        result = benchmark(_benchmark_ttl, ttl=ttl)
        results[ttl] = result.stats["p99"]

    assert results[1] < results[10] < results[3600]  # Latence augmente avec TTL court

# Tests d'exceptions
def test_cache_full_exception(cache_10k_100_threads):
    """Test de dépassement de capacité du cache"""
    for i in range(10_000):
        cache_10k_100_threads.set(f"key_{i}", f"value_{i}")
    with pytest.raises(MemoryError):
        cache_10k_100_threads.set("key_overflow", "value_overflow")


def test_invalid_ttl_exception():
    """Test de TTL invalide"""
    cache = LRUCacheWithTTL(max_size=100)
    with pytest.raises(ValueError):
        cache.set("key", "value", ttl=-1)


def test_concurrent_modification(cache_10k_100_threads):
    """Test de modification concurrente du cache"""
    def _set_key(i):
        cache_10k_100_threads.set(f"key_{i}", f"value_{i}")

    threads = []
    for i in range(100):
        t = threading.Thread(target=_set_key, args=(i,))
        threads.append(t)
        t.start()

    for t in threads:
        t.join()

    assert len(cache_10k_100_threads._cache) == 100

